CREATE TABLE [dbo].[MealDiary](
	[MealDiaryId] [int] IDENTITY(1,1) NOT NULL,
	[UserId] [uniqueidentifier] NOT NULL,
	[EatenDate] [date] NOT NULL,
	[MealTypeId] [int] NOT NULL,
	[FoodItemId] [int] NULL,
	[UserDishId] [int] NULL,
	[UserFoodItemId] [int] NULL,
	[RecipeId] [int] NULL,
	[ServingUnitId] [int] NULL,
	[PortionQuantity] [decimal](10, 2) NULL,
	[Grams] [decimal](10, 2) NOT NULL,
	[Calories] [decimal](10, 2) NOT NULL,
	[Protein] [decimal](10, 2) NOT NULL,
	[Carb] [decimal](10, 2) NOT NULL,
	[Fat] [decimal](10, 2) NOT NULL,
	[Note] [nvarchar](500) NULL,
	[PhotoUrl] [nvarchar](500) NULL,
	[SourceMethod] [nvarchar](30) NULL,
	[CreatedAt] [datetime2](3) NOT NULL,
	[UpdatedAt] [datetime2](3) NOT NULL,
	[IsDeleted] [bit] NOT NULL,
 CONSTRAINT [PK_MealDiary] PRIMARY KEY CLUSTERED 
(
	[MealDiaryId] ASC
)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON, OPTIMIZE_FOR_SEQUENTIAL_KEY = OFF) ON [PRIMARY]
) ON [PRIMARY]
