/****** Object:  View [dbo].[vw_DailyNutritionTotals]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_DailyNutritionTotals] AS
SELECT UserId, EatenDate,
       SUM(Calories) AS TotalCalories, SUM(Protein) AS TotalProtein, SUM(Carb) AS TotalCarb, SUM(Fat) AS TotalFat
FROM dbo.MealDiary
WHERE IsDeleted=0
GROUP BY UserId, EatenDate;
GO
/****** Object:  View [dbo].[vw_WeeklyNutritionTotals]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_WeeklyNutritionTotals] AS
SELECT UserId,
       DATEADD(day, - (DATEPART(weekday, EatenDate)+5)%7, CAST(EatenDate AS DATE)) AS WeekStart, -- Monday-based
       SUM(Calories) AS TotalCalories, SUM(Protein) AS TotalProtein, SUM(Carb) AS TotalCarb, SUM(Fat) AS TotalFat
FROM dbo.MealDiary
WHERE IsDeleted=0
GROUP BY UserId, DATEADD(day, - (DATEPART(weekday, EatenDate)+5)%7, CAST(EatenDate AS DATE));
GO
/****** Object:  View [dbo].[vw_DailyMacroShare]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_DailyMacroShare] AS
SELECT UserId, EatenDate,
       SUM(Calories) AS TotalCalories, SUM(Protein) AS TotalProtein, SUM(Carb) AS TotalCarb, SUM(Fat) AS TotalFat,
       CAST(CASE WHEN SUM(Calories)=0 THEN 0 ELSE (SUM(Protein)*4.0)/NULLIF(SUM(Calories),0) END AS DECIMAL(5,4)) AS ProteinShare,
       CAST(CASE WHEN SUM(Calories)=0 THEN 0 ELSE (SUM(Carb)*4.0)/NULLIF(SUM(Calories),0) END AS DECIMAL(5,4))    AS CarbShare,
       CAST(CASE WHEN SUM(Calories)=0 THEN 0 ELSE (SUM(Fat)*9.0)/NULLIF(SUM(Calories),0) END AS DECIMAL(5,4))     AS FatShare
FROM dbo.MealDiary
WHERE IsDeleted=0
GROUP BY UserId, EatenDate;

GO
/****** Object:  View [dbo].[vw_MonthlyTotals]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_MonthlyTotals] AS
SELECT UserId, CAST(DATEFROMPARTS(YEAR(EatenDate), MONTH(EatenDate), 1) AS DATE) AS Month,
       SUM(Calories) AS TotalCalories, SUM(Protein) AS TotalProtein, SUM(Carb) AS TotalCarb, SUM(Fat) AS TotalFat,
       COUNT(*) AS EntryCount
FROM dbo.MealDiary
WHERE IsDeleted=0
GROUP BY UserId, DATEFROMPARTS(YEAR(EatenDate), MONTH(EatenDate), 1);
GO
