/****** Object:  View [dbo].[vw_TargetProgress]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[vw_TargetProgress] AS
SELECT
    d.UserId, d.EatenDate,
    d.TotalCalories, d.TotalProtein, d.TotalCarb, d.TotalFat,
    t.TargetCalories, t.TargetProtein, t.TargetCarb, t.TargetFat,
    CAST(d.TotalCalories - t.TargetCalories AS INT) AS CalorieDelta,
    CAST(d.TotalProtein  - t.TargetProtein  AS INT) AS ProteinDelta,
    CAST(d.TotalCarb     - t.TargetCarb     AS INT) AS CarbDelta,
    CAST(d.TotalFat      - t.TargetFat      AS INT) AS FatDelta
FROM (
    SELECT UserId, EatenDate,
           SUM(Calories) AS TotalCalories, SUM(Protein) AS TotalProtein, SUM(Carb) AS TotalCarb, SUM(Fat) AS TotalFat
    FROM dbo.MealDiary WHERE IsDeleted=0 GROUP BY UserId, EatenDate
) d
JOIN dbo.NutritionTarget t
  ON t.UserId = d.UserId
 AND (t.EffectiveFrom = d.EatenDate OR (t.EffectiveFrom <= d.EatenDate AND (t.EffectiveTo IS NULL OR t.EffectiveTo >= d.EatenDate)));

GO
