/****** Object:  View [dbo].[vw_AiFoodMap]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[vw_AiFoodMap]
AS
SELECT
    M.Label,                       -- nhãn AI (lowercase, ví dụ: "banana")
    M.MinConfidence,
    M.FoodItemId,
    F.FoodName,
    F.CaloriesPer100g,
    F.ProteinPer100g,
    F.FatPer100g,
    F.CarbPer100g,
    F.IsActive,
    F.IsDeleted
FROM dbo.AiLabelMap M
LEFT JOIN dbo.FoodItem F
    ON F.FoodItemId = M.FoodItemId;
GO
