/****** Object:  StoredProcedure [dbo].[sp_Food_Search]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_Food_Search]
    @q NVARCHAR(200) = N'',
    @page INT = 1,
    @size INT = 20,
    @total INT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    IF @page < 1 SET @page = 1;
    IF @size < 1 SET @size = 20;
    DECLARE @offset INT = (@page-1)*@size;

    WITH s AS (
        SELECT FoodItemId, FoodName, CaloriesPer100g, ProteinPer100g, CarbPer100g, FatPer100g, IsActive
        FROM dbo.FoodItem
        WHERE IsDeleted=0 AND (@q=N'' OR FoodName LIKE N'%' + @q + N'%')
    )
    SELECT @total = COUNT(*) FROM s;

    SELECT FoodItemId, FoodName, CaloriesPer100g, ProteinPer100g, CarbPer100g, FatPer100g, IsActive
    FROM s
    ORDER BY FoodName
    OFFSET @offset ROWS FETCH NEXT @size ROWS ONLY;
END
GO
/****** Object:  StoredProcedure [dbo].[sp_MealDiary_AddEntry]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_MealDiary_AddEntry]
    @UserId UNIQUEIDENTIFIER,
    @EatenDate DATE,
    @MealTypeId INT,

    @FoodItemId INT = NULL,
    @UserDishId INT = NULL,
    @RecipeId INT = NULL,
    @UserFoodItemId INT = NULL,

    @Amount DECIMAL(10,2) = NULL,        -- số lượng (g cho FoodItem/UserDish/Recipe; g hoặc ml cho UserFoodItem)
    @Note NVARCHAR(500) = NULL, @PhotoUrl NVARCHAR(500) = NULL,
    @SourceMethod NVARCHAR(30) = N'Manual'
AS
BEGIN
    SET NOCOUNT ON;

    IF ((CASE WHEN @FoodItemId IS NOT NULL THEN 1 ELSE 0 END) +
        (CASE WHEN @UserDishId IS NOT NULL THEN 1 ELSE 0 END) +
        (CASE WHEN @RecipeId   IS NOT NULL THEN 1 ELSE 0 END) +
        (CASE WHEN @UserFoodItemId IS NOT NULL THEN 1 ELSE 0 END)) <> 1
    BEGIN
        RAISERROR(N'Chọn đúng 1 nguồn: FoodItemId | UserDishId | RecipeId | UserFoodItemId.', 16, 1);
        RETURN;
    END

    IF (@Amount IS NULL OR @Amount < 0)
    BEGIN
        RAISERROR(N'@Amount phải có giá trị không âm (theo g hoặc ml).',16,1);
        RETURN;
    END

    DECLARE @Cal DECIMAL(10,2)=0, @P DECIMAL(10,2)=0, @C DECIMAL(10,2)=0, @F DECIMAL(10,2)=0;

    -- 5.1: UserFoodItem (chuẩn theo 100 g/ml)
    IF @UserFoodItemId IS NOT NULL
    BEGIN
        DECLARE @Cal100 DECIMAL(10,2), @P100 DECIMAL(10,2), @C100 DECIMAL(10,2), @F100 DECIMAL(10,2);
        SELECT @Cal100=CaloriesPer100, @P100=ProteinPer100, @C100=CarbPer100, @F100=FatPer100
        FROM dbo.UserFoodItem WHERE UserFoodItemId=@UserFoodItemId;

        SET @Cal = @Cal100 * @Amount / 100.0;
        SET @P   = @P100   * @Amount / 100.0;
        SET @C   = @C100   * @Amount / 100.0;
        SET @F   = @F100   * @Amount / 100.0;

        INSERT INTO dbo.MealDiary
        (UserId, EatenDate, MealTypeId, UserFoodItemId,
         Grams, Calories, Protein, Carb, Fat, Note, PhotoUrl, SourceMethod)
        VALUES
        (@UserId, @EatenDate, @MealTypeId, @UserFoodItemId,
         @Amount, @Cal, @P, @C, @F, @Note, @PhotoUrl, @SourceMethod);

        SELECT SCOPE_IDENTITY() AS MealDiaryId, @Cal AS Calories, @P AS Protein, @C AS Carb, @F AS Fat;
        RETURN;
    END

    -- 5.2: FoodItem (chuẩn theo 100 g)
    IF @FoodItemId IS NOT NULL
    BEGIN
        DECLARE @Cal100F DECIMAL(10,2), @P100F DECIMAL(10,2), @C100F DECIMAL(10,2), @F100F DECIMAL(10,2);
        SELECT @Cal100F=CaloriesPer100g, @P100F=ProteinPer100g, @C100F=CarbPer100g, @F100F=FatPer100g FROM dbo.FoodItem WHERE FoodItemId=@FoodItemId;

        SET @Cal = @Cal100F * @Amount / 100.0;
        SET @P   = @P100F   * @Amount / 100.0;
        SET @C   = @C100F   * @Amount / 100.0;
        SET @F   = @F100F   * @Amount / 100.0;

        INSERT INTO dbo.MealDiary
        (UserId, EatenDate, MealTypeId, FoodItemId,
         Grams, Calories, Protein, Carb, Fat, Note, PhotoUrl, SourceMethod)
        VALUES
        (@UserId, @EatenDate, @MealTypeId, @FoodItemId,
         @Amount, @Cal, @P, @C, @F, @Note, @PhotoUrl, @SourceMethod);

        SELECT SCOPE_IDENTITY() AS MealDiaryId, @Cal AS Calories, @P AS Protein, @C AS Carb, @F AS Fat;
        RETURN;
    END

    -- 5.3: UserDish (tổng hợp từ các ingredient -> quy về /100g)
    IF @UserDishId IS NOT NULL
    BEGIN
        DECLARE @TotalG DECIMAL(10,2) = (SELECT SUM(Grams) FROM dbo.UserDishIngredient WHERE UserDishId=@UserDishId);
        IF @TotalG IS NULL OR @TotalG=0 RAISERROR(N'Món người dùng chưa có thành phần.',16,1);

        DECLARE @Cal100D DECIMAL(10,2), @P100D DECIMAL(10,2), @C100D DECIMAL(10,2), @F100D DECIMAL(10,2);
        SELECT @Cal100D = SUM(fi.CaloriesPer100g * di.Grams/100.0),
               @P100D   = SUM(fi.ProteinPer100g  * di.Grams/100.0),
               @C100D   = SUM(fi.CarbPer100g     * di.Grams/100.0),
               @F100D   = SUM(fi.FatPer100g      * di.Grams/100.0)
        FROM dbo.UserDishIngredient di
        JOIN dbo.FoodItem fi ON fi.FoodItemId=di.FoodItemId
        WHERE di.UserDishId=@UserDishId;

        -- Quy về trên 100g món
        SET @Cal100D=@Cal100D*(100.0/@TotalG);
        SET @P100D=@P100D*(100.0/@TotalG);
        SET @C100D=@C100D*(100.0/@TotalG);
        SET @F100D=@F100D*(100.0/@TotalG);

        SET @Cal = @Cal100D * @Amount / 100.0;
        SET @P   = @P100D   * @Amount / 100.0;
        SET @C   = @C100D   * @Amount / 100.0;
        SET @F   = @F100D   * @Amount / 100.0;

        INSERT INTO dbo.MealDiary
        (UserId, EatenDate, MealTypeId, UserDishId,
         Grams, Calories, Protein, Carb, Fat, Note, PhotoUrl, SourceMethod)
        VALUES
        (@UserId, @EatenDate, @MealTypeId, @UserDishId,
         @Amount, @Cal, @P, @C, @F, @Note, @PhotoUrl, @SourceMethod);

        SELECT SCOPE_IDENTITY() AS MealDiaryId, @Cal AS Calories, @P AS Protein, @C AS Carb, @F AS Fat;
        RETURN;
    END

    -- 5.4: Recipe (tổng hợp từ các ingredient -> quy về /100g)
    IF @RecipeId IS NOT NULL
    BEGIN
        DECLARE @TotalGR DECIMAL(10,2) = (SELECT SUM(Grams) FROM dbo.RecipeIngredient WHERE RecipeId=@RecipeId);
        IF @TotalGR IS NULL OR @TotalGR=0 RAISERROR(N'Công thức chưa có nguyên liệu.',16,1);

        DECLARE @Cal100R DECIMAL(10,2), @P100R DECIMAL(10,2), @C100R DECIMAL(10,2), @F100R DECIMAL(10,2);
        SELECT @Cal100R = SUM(fi.CaloriesPer100g * ri.Grams/100.0),
               @P100R   = SUM(fi.ProteinPer100g  * ri.Grams/100.0),
               @C100R   = SUM(fi.CarbPer100g     * ri.Grams/100.0),
               @F100R   = SUM(fi.FatPer100g      * ri.Grams/100.0)
        FROM dbo.RecipeIngredient ri
        JOIN dbo.FoodItem fi ON fi.FoodItemId=ri.FoodItemId
        WHERE ri.RecipeId=@RecipeId;

        -- Quy về trên 100g món
        SET @Cal100R=@Cal100R*(100.0/@TotalGR);
        SET @P100R=@P100R*(100.0/@TotalGR);
        SET @C100R=@C100R*(100.0/@TotalGR);
        SET @F100R=@F100R*(100.0/@TotalGR);

        SET @Cal = @Cal100R * @Amount / 100.0;
        SET @P   = @P100R   * @Amount / 100.0;
        SET @C   = @C100R   * @Amount / 100.0;
        SET @F   = @F100R   * @Amount / 100.0;

        INSERT INTO dbo.MealDiary
        (UserId, EatenDate, MealTypeId, RecipeId,
         Grams, Calories, Protein, Carb, Fat, Note, PhotoUrl, SourceMethod)
        VALUES
        (@UserId, @EatenDate, @MealTypeId, @RecipeId,
         @Amount, @Cal, @P, @C, @F, @Note, @PhotoUrl, @SourceMethod);

        SELECT SCOPE_IDENTITY() AS MealDiaryId, @Cal AS Calories, @P AS Protein, @C AS Carb, @F AS Fat;
        RETURN;
    END
END;

GO
/****** Object:  StoredProcedure [dbo].[sp_MealDiary_DeleteSoft]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_MealDiary_DeleteSoft]
    @MealDiaryId INT
AS
BEGIN
    UPDATE dbo.MealDiary SET IsDeleted=1 WHERE MealDiaryId=@MealDiaryId;
END

GO
/****** Object:  StoredProcedure [dbo].[sp_MealDiary_Restore]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_MealDiary_Restore]
    @MealDiaryId INT
AS
BEGIN
    UPDATE dbo.MealDiary SET IsDeleted=0 WHERE MealDiaryId=@MealDiaryId;
END

GO
/****** Object:  StoredProcedure [dbo].[sp_UserDish_Create]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_UserDish_Create]
    @UserId UNIQUEIDENTIFIER,
    @DishName NVARCHAR(255),
    @Description NVARCHAR(500) = NULL,
    @IngredientsJson NVARCHAR(MAX) -- [{"FoodItemId":1,"Grams":150.0}, ...]
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserDishId INT;
    INSERT INTO dbo.UserDish(UserId, DishName, Description) VALUES (@UserId, @DishName, @Description);
    SET @UserDishId = SCOPE_IDENTITY();

    ;WITH cte AS (
        SELECT
            TRY_CAST(j.[FoodItemId] AS INT) AS FoodItemId,
            TRY_CAST(j.[Grams] AS DECIMAL(10,2)) AS Grams
        FROM OPENJSON(@IngredientsJson)
        WITH (FoodItemId INT '$.FoodItemId', Grams DECIMAL(10,2) '$.Grams') j
    )
    INSERT INTO dbo.UserDishIngredient(UserDishId, FoodItemId, Grams)
    SELECT @UserDishId, FoodItemId, Grams
    FROM cte
    WHERE FoodItemId IS NOT NULL AND Grams IS NOT NULL;

    SELECT @UserDishId AS UserDishId;
END

GO
/****** Object:  StoredProcedure [dbo].[sp_UserFood_Create]    Script Date: 12/14/2025 10:12:55 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE   PROCEDURE [dbo].[sp_UserFood_Create]
    @UserId UNIQUEIDENTIFIER,
    @FoodName NVARCHAR(255),
    @ThumbnailUrl NVARCHAR(500) = NULL,
    @UnitType CHAR(2),               -- 'g' hoặc 'ml'
    @CaloriesPer100 DECIMAL(10,2),
    @ProteinPer100  DECIMAL(10,2),
    @CarbPer100     DECIMAL(10,2),
    @FatPer100      DECIMAL(10,2)
AS
BEGIN
    SET NOCOUNT ON;

    IF (@UnitType NOT IN ('g','ml'))
    BEGIN
        RAISERROR(N'UnitType phải là ''g'' hoặc ''ml''.',16,1);
        RETURN;
    END

    INSERT INTO dbo.UserFoodItem
    (UserId, FoodName, ThumbnailUrl, UnitType, CaloriesPer100, ProteinPer100, CarbPer100, FatPer100)
    VALUES
    (@UserId, @FoodName, @ThumbnailUrl, @UnitType, @CaloriesPer100, @ProteinPer100, @CarbPer100, @FatPer100);

    SELECT SCOPE_IDENTITY() AS UserFoodItemId;
END;

GO
